+    /// Round each datetime up (ceil) to the given frequency.
+    ///
+    /// Matches `pd.Series.dt.ceil(freq)`. Supported frequencies:
+    /// "D" (day), "h" (hour), "min" (minute), "s" (second).
+    pub fn ceil(&self, freq: &str) -> Result<Series, FrameError> {
